{
  "permissions": {
    "allow": [
      "Bash(git *)",
      "Bash(gh *)"
    ],
    "deny": []
  },
  "extraKnownMarketplaces": {
    "claude-code-plugins": {
      "source": {
        "source": "github",
        "repo": "anthropics/claude-code"
      },
      "autoUpdate": true
    },
    "anthropic-agent-skills": {
      "source": {
        "source": "github",
        "repo": "anthropics/skills"
      },
      "autoUpdate": true
    },
    "claude-code-workflows": {
      "source": {
        "source": "github",
        "repo": "wshobson/agents"
      },
      "autoUpdate": false
    }
  },
  "enabledPlugins": {
    "code-review@claude-code-plugins": true,
    "pr-review-toolkit@claude-code-plugins": true,
    "commit-commands@claude-code-plugins": true,
    "feature-dev@claude-code-plugins": true,
    "frontend-design@claude-code-plugins": true,
    "hookify@claude-code-plugins": true,
    "plugin-dev@claude-code-plugins": true,
    "agent-sdk-dev@claude-code-plugins": true,
    "security-guidance@claude-code-plugins": true,
    "ralph-wiggum@claude-code-plugins": true,
    "explanatory-output-style@claude-code-plugins": true,
    "learning-output-style@claude-code-plugins": true,
    "claude-opus-4-5-migration@claude-code-plugins": true,
    "document-skills@anthropic-agent-skills": true,
    "example-skills@anthropic-agent-skills": true,
    "hr-legal-compliance@claude-code-workflows": true,
    "security-compliance@claude-code-workflows": true
  },
  "hooks": {
    "SessionStart": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "bash \"$CLAUDE_PROJECT_DIR/setup/session-start.sh\""
          },
          {
            "type": "command",
            "command": "bash \"$CLAUDE_PROJECT_DIR/skills/kb-memory/kb-inject.sh\" session"
          }
        ]
      }
    ],
    "UserPromptSubmit": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "OCTOOLS_DIR=\"$CLAUDE_PROJECT_DIR\" bash \"$CLAUDE_PROJECT_DIR/setup/octools-sync.sh\""
          }
        ]
      }
    ],
    "PreCompact": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "bash \"$CLAUDE_PROJECT_DIR/skills/kb-memory/kb-inject.sh\" precompact"
          }
        ]
      }
    ],
    "Stop": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "bash \"$CLAUDE_PROJECT_DIR/skills/kb-memory/kb-inject.sh\" stop"
          },
          {
            "type": "command",
            "command": "node \"$CLAUDE_PROJECT_DIR/skills/fleet-telemetry/telemetry.mjs\" session-end"
          },
          {
            "type": "command",
            "command": "node \"$CLAUDE_PROJECT_DIR/skills/kb-memory/reflect.mjs\" --commit"
          }
        ]
      }
    ]
  }
}
